targets.expr:
100 *
sum by (service) (
  jvm_memory_used_bytes{area="heap", service=~"$service_name", environment=~"$env"}
)
/
sum by (service) (
  jvm_memory_max_bytes{area="heap", service=~"$service_name", environment=~"$env"}
)

sum by (service, method, uri) (
  rate(http_server_requests_seconds_count{service=~"$service_name", environment=~"$env", uri!="UNKNOWN", uri!="/actuator/prometheus"}[$__rate_interval])
)
